// Нормалізація вхідних даних
let input = $input.all()[0].json;
let payload = {};

if (input.query) {
  // Якщо прийшло з Chat Trigger
  payload.message = input.query;
} else {
  // Якщо прийшло з Webhook
  payload = input.body || input;
  if (payload.contact) {
    payload.contact.email = payload.contact.email ? payload.contact.email.trim().toLowerCase() : 'N/A';
    payload.contact.name = payload.contact.name ? payload.contact.name.trim() : 'N/A';
  }
}

return [{ json: { normalized_payload: JSON.stringify(payload) } }];

// Отримуємо сирий текст від AI
const responseText = items[0].json.text || "";

// 1. Відновлюємо оригінальний текст запиту та визначаємо джерело
let originalMessage = 'Не вказано';
let leadSource = 'Вбудований чат';

try {
  const rawPayload = $('Data Normalization').first().json.normalized_payload;
  const parsedPayload = typeof rawPayload === 'string' ? JSON.parse(rawPayload) : rawPayload;

  originalMessage = parsedPayload.chatInput || parsedPayload.message || 'Не вказано';

  // Визначаємо звідки прийшов лід
  if (parsedPayload.chatInput) {
    leadSource = 'Вбудований чат';
  } else if (parsedPayload.action || parsedPayload.message) {
    leadSource = 'Webhook / Telegram';
  }
} catch (e) {
  console.log('Помилка відновлення вхідних даних:', e);
}

// 2. Надійно витягуємо JSON із відповіді AI (шукаємо текст між першою { та останньою })
let parsedAI = {};
try {
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  parsedAI = JSON.parse(jsonMatch ? jsonMatch[0] : responseText);
} catch (e) {
  console.log('Не вдалося розпарсити відповідь моделі, використовуємо дефолтні значення:', e);
}

// 3. Валідація значень із фіксованих списків
const validTemps = ['Hot', 'Warm', 'Cold'];
const validCats = ['B2B', 'B2C'];

// 4. Формуємо об'єкт з полями для Google Sheets та Telegram
return [{
  json: {
    // Точні назви змінних, які очікує ваша нода "Format Telegram Message"
    leadName: parsedAI.name || 'Не вказано',
    leadEmail: parsedAI.email || 'Не вказано',
    companyName: parsedAI.company || 'Не вказано',
    phoneNumber: parsedAI.phone || 'Не вказано',
    leadSource: leadSource,
    leadSummary: parsedAI.summary || 'Запит на автоматизацію',
    leadTemperature: validTemps.includes(parsedAI.lead_temperature) ? parsedAI.lead_temperature : 'Warm',
    leadCategory: validCats.includes(parsedAI.type) ? parsedAI.type : 'B2B',
    budget: parsedAI.budget || 'Не вказано',
    inquiryMessage: originalMessage,

    // Поля для вашої Google-таблиці
    text: responseText, 
    processedTime: new Date().toISOString(), // Для колонки "processedTime"
    processedTimestamp: new Date().toISOString() // Для сумісності з Telegram-шаблоном
  }
}];

// Format HTML message for Telegram
const data = items[0].json;

const tempEmoji = {
  'Hot': '🔥',
  'Warm': '🌤️',
  'Cold': '❄️'
};

const catIcon = data.leadCategory === 'B2B' ? '🏢' : '👤';
const tempIcon = tempEmoji[data.leadTemperature] || '❓';

const htmlMessage = `
<b>🎯 New Lead Processed</b>

<b>Lead Details:</b>
<b>Name:</b> ${data.leadName || 'Не вказано'}
<b>Email:</b> ${data.leadEmail || 'Не вказано'}
<b>Company:</b> ${data.companyName || 'Не вказано'}
<b>Phone:</b> ${data.phoneNumber || 'Не вказано'}
<b>Source:</b> ${data.leadSource || 'Вбудований чат'}

<b>Analysis:</b>
<b>Summary:</b> <em>${data.leadSummary}</em>
<b>Temperature:</b> ${tempIcon} ${data.leadTemperature}
<b>Category:</b> ${catIcon} ${data.leadCategory}
<b>Budget:</b> ${data.budget || 'Not specified'}

<b>Inquiry:</b>
<em>${data.inquiryMessage}</em>

<b>Processed:</b> ${new Date(data.processedTimestamp).toLocaleString()}
`;

return [{
  json: {
    ...data,
    htmlMessage: htmlMessage,
    chatId: '{{ $secrets.TELEGRAM_CHAT_ID }}'
  }
}];

return [{
  json: {
    text: "Дякуємо! Ваша заявка прийнята. Найближчим часом з вами зв'яжеться менеджер."
  }
}];
